import{_ as e,z as i,m as s,ap as t}from"./chunks/framework.BtwXvyX_.js";const k=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/guide/faq.md","filePath":"markdown/guide/faq.md","lastUpdated":1774851650000}'),l={name:"markdown/guide/faq.md"};function n(d,a,r,o,p,h){return s(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="stream-为什么有时候是布尔值-有时候是对象" tabindex="-1"><code>stream</code> 为什么有时候是布尔值，有时候是对象？ <a class="header-anchor" href="#stream-为什么有时候是布尔值-有时候是对象" aria-label="Permalink to &quot;`stream` 为什么有时候是布尔值，有时候是对象？&quot;">​</a></h2><p>这是当前适配器的兼容设计。</p><h3 id="stream-true" tabindex="-1"><code>stream: true</code> <a class="header-anchor" href="#stream-true" aria-label="Permalink to &quot;`stream: true`&quot;">​</a></h3><p>表示使用适配器内部的快捷流式首包写法，也就是自动附加：</p><ul><li><code>state = 1</code></li></ul><h3 id="stream" tabindex="-1"><code>stream: { ... }</code> <a class="header-anchor" href="#stream" aria-label="Permalink to &quot;`stream: { ... }`&quot;">​</a></h3><p>表示你自己直接传 QQ 官方原始流式对象。</p><p>例如：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#E06C75;">stream</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: {</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#E06C75;">  state</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#E06C75;">  id</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#24292E;--shiki-dark:#E06C75;">streamId</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#E06C75;">  index</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">,</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#E06C75;">  reset</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">}</span></span></code></pre></div><p>也就是说，<code>stream</code> 现在统一只有一个名字，只是支持两种值类型。</p><h2 id="stream-true-为什么不会自动结束" tabindex="-1"><code>stream: true</code> 为什么不会自动结束？ <a class="header-anchor" href="#stream-true-为什么不会自动结束" aria-label="Permalink to &quot;`stream: true` 为什么不会自动结束？&quot;">​</a></h2><p>这是当前刻意保留的行为。 适配器只负责帮你进入流式状态，不自动决定何时结束。</p><p>原因是不同消息的结束时机很难统一，而且自动补 <code>state = 10</code> 容易导致：</p><ul><li>重复消息</li><li>空消息</li><li>主动消息权限错误</li><li>不同客户端表现不一致</li></ul><p>所以现在如果你要结束流式，请自己传原始 <code>stream</code> 对象。</p><h2 id="为什么-windows-qq-和手机-qq-的-markdown-显示不一样" tabindex="-1">为什么 Windows QQ 和手机 QQ 的 Markdown 显示不一样？ <a class="header-anchor" href="#为什么-windows-qq-和手机-qq-的-markdown-显示不一样" aria-label="Permalink to &quot;为什么 Windows QQ 和手机 QQ 的 Markdown 显示不一样？&quot;">​</a></h2><p>这是 QQ 客户端本身的差异。 同一条原生 Markdown 消息，在不同端的渲染和复制结果可能不同，尤其是下面这些内容：</p><ul><li>方括号链接</li><li>分隔线</li><li>代码块</li><li>蓝字按钮</li></ul><p>如果某类消息需要跨端显示尽量一致，建议：</p><ul><li>保持 Markdown 简单</li><li>少用复杂链接语法</li><li>必要时关闭 <code>autoStreamText</code></li></ul><h2 id="autostreamtext-开了以后-为什么普通文本看起来像-markdown" tabindex="-1"><code>autoStreamText</code> 开了以后，为什么普通文本看起来像 Markdown？ <a class="header-anchor" href="#autostreamtext-开了以后-为什么普通文本看起来像-markdown" aria-label="Permalink to &quot;`autoStreamText` 开了以后，为什么普通文本看起来像 Markdown？&quot;">​</a></h2><p>因为这个开关的实现方式就是：</p><ul><li>检测到纯文本</li><li>改成 QQ 原生 Markdown 消息发送</li><li>再附加流式首包</li></ul><p>所以开启后，本质上已经不是“普通文本消息”了。</p><h2 id="私聊-channelid-为什么是-private-xxxx" tabindex="-1">私聊 <code>channelId</code> 为什么是 <code>private:xxxx</code>？ <a class="header-anchor" href="#私聊-channelid-为什么是-private-xxxx" aria-label="Permalink to &quot;私聊 `channelId` 为什么是 `private:xxxx`？&quot;">​</a></h2><p>这是适配器内部约定的私聊频道 ID 格式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>private:{userId}</span></span></code></pre></div><p>这样可以明确区分：</p><ul><li>群聊 <code>channelId</code></li><li>私聊 <code>channelId</code></li></ul><p>并且你可以统一调用：</p><ul><li><code>sendMessage(channelId, ...)</code></li><li><code>deleteMessage(channelId, messageId)</code></li></ul><p>适配器会在内部自动还原真实 QQ 用户 ID。</p><h2 id="qq-zombied-connection-是什么" tabindex="-1"><code>qq zombied connection</code> 是什么？ <a class="header-anchor" href="#qq-zombied-connection-是什么" aria-label="Permalink to &quot;`qq zombied connection` 是什么？&quot;">​</a></h2><p>这是心跳检测发现连接已经僵死。 适配器现在会在这种情况下立即重连，而不是完全依赖默认的重试间隔。</p><p>所以看到这条日志不一定代表插件出故障，更像是一次主动的快速自恢复。</p><h2 id="为什么群里能拿到用户名-私聊里却拿不到" tabindex="-1">为什么群里能拿到用户名，私聊里却拿不到？ <a class="header-anchor" href="#为什么群里能拿到用户名-私聊里却拿不到" aria-label="Permalink to &quot;为什么群里能拿到用户名，私聊里却拿不到？&quot;">​</a></h2><p>这是 QQ 官方事件内容本身的差异。 有些 WebSocket 事件会带 <code>author.username</code>，有些不会。</p><p>适配器现在会：</p><ul><li>优先使用事件里带来的用户名</li><li>写入数据库</li><li>后续再从缓存或数据库回填到 <code>session.username</code></li></ul><p>所以第一次可能拿不到，后面同一用户就更稳定了。</p>',41)])])}const u=e(l,[["render",n]]);export{k as __pageData,u as default};
